INSERT INTO guia.dbo.ElementosAstro (Nombre,Icono,Esencia,Descripcion) VALUES
	 (N'Fuego',N'🔥',N'La chispa de la vida',N'Representa el entusiasmo, la voluntad, la pasión y el impulso creativo que inicia todo movimiento.'),
	 (N'Tierra',N'🌍',N'La solidez de la forma',N'Representa la manifestación práctica, la paciencia, el mundo material y la capacidad de dar frutos constantes.'),
	 (N'Aire',N'💨',N'El aliento del pensamiento',N'Representa la comunicación, el intelecto, las ideas sociales y la capacidad de observar la realidad objetivamente.'),
	 (N'Agua',N'💧',N'El flujo de la emoción',N'Representa la sensibilidad profunda, la intuición, los sueños y la conexión psíquica con los demás.');
